// Extraer token y preparar el payload para Wazuh
const token = $input.first().json.data.token;
const alert = $('Webhook - Recibir Alerta').first().json.body;
const threatInfo = alert.threat_intel || {};

const wazuhAlert = {
  timestamp: alert.timestamp || new Date().toISOString(),
  rule: {
    id: alert.rule_id || 100001,
    level: alert.severity === 'critical' ? 12 :
           alert.severity === 'high' ? 8 :
           alert.severity === 'medium' ? 5 : 3,
    description: alert.description || 'No description',
    mitre: {
      tactic: alert.category === 'authentication_failure' ? 'Credential Access' : 'Unknown',
      technique: alert.rule_name || 'Unknown'
    }
  },
  agent: { id: '001', name: 'n8n-workflow' },
  data: {
    srcip: alert.source_ip || '0.0.0.0',
    rule_name: alert.rule_name || 'Unknown',
    risk_score: alert.risk_score || 0,
    risk_level: alert.risk_level || 'LOW',
    event_count: alert.event_count || 1,
    threat_intel: {
      reputation: threatInfo.threat_info?.reputation || 'unknown',
      confidence: threatInfo.threat_info?.confidence || 0,
      is_private_ip: threatInfo.is_private_ip || false,
      geo_info: threatInfo.geo_info || {}
    }
  },
  location: 'n8n_workflow',
  full_log: JSON.stringify(alert.raw_log || alert)
};

return [{ json: { 
  wazuh_token: token, 
  wazuh_alert: JSON.stringify(wazuhAlert), 
  original_alert: alert 
} }]
